from typing import Dict, Any, Callable, Optional
from .handler_registry import HandlerRegistry

Request = Dict[str, Any]
Response = Dict[str, Any]
Handler = Callable[[Request], Response]

class RequestDispatcher:
    def __init__(self, registry: HandlerRegistry):
        self.registry = registry

    def dispatch(self, request: Request) -> Response:
        handler: Optional[Handler] = self.registry.get_handler(request["type"])
        if handler:
            return handler(request)
        return {"success": False, "error": f"No handler for type {request['type']}"}

from typing import Dict, Any, Callable, Optional

Request = Dict[str, Any]
Response = Dict[str, Any]
Handler = Callable[[Request], Response]

class HandlerRegistry:
    def __init__(self):
        self._handlers: Dict[str, Handler] = {}

    def register(self, type_: str, handler: Handler) -> None:
        self._handlers[type_] = handler

    def get_handler(self, type_: str) -> Optional[Handler]:
        return self._handlers.get(type_)

