from typing import Dict, Any

class CoreAdapter:
    @staticmethod
    def handle(request: Dict[str, Any]) -> Dict[str, Any]:
        data = request['data']
        op = data.get('operation')
        if op == 'sum':
            return {'success': True, 'result': data['a'] + data['b']}
        if op == 'multiply':
            return {'success': True, 'result': data['a'] * data['b']}
        return {'success': False, 'error': f'Unknown op: {op}'}

