def validate_request(request: Dict[str, Any]) -> bool:
    required = ['id', 'type', 'data']
    return all(k in request for k in required) and isinstance(request['data'], dict)

from typing import Dict, Any

def normalize_request(request: Dict[str, Any]) -> Dict[str, Any]:
    if 'context' not in request: request['context'] = {}
    request['data'] = {k.lower(): v for k, v in request['data'].items()}
    return request

